always @(posedge clk or posedge rstTrigger)
	if (rstTrigger || !locked) begin
		rst <= 1'b1;
	end
	else if (rst) begin
		rst <= (count >= 10000 ? 1'b0 : 1'b1);
	end
	else begin
		rst <= 1'b0;
	end

always @(posedge clk or posedge rstTrigger)
	if (rstTrigger || !locked) begin
		count <= 0;
		rst <= 1'b1;
	end
	else if (rst) begin
		count <= count + 1;
		rst <= (count >= CYCLE_OF_RESET_SEQUENCE ? 1'b0 : 1'b1);
	end
